import React from 'react';

function About() {
  return (
    <div className="p-8 max-w-4xl mx-auto min-h-screen">
      <h1 className="text-3xl font-bold mb-4">About HEALink</h1>
      <p className="text-gray-700">
        HEALink is dedicated to connecting people with essential healthcare services, including diagnostics,
        blood bank information, online consultations, and timely medicine delivery. Our mission is to make
        healthcare accessible and efficient for everyone.
      </p>
    </div>
  );
}

export default About;
